///   4. Stop() is now async to await graceful shutdown instead of Thread.Sleep.
///   5. IDisposable implemented to deterministically release the CancellationTokenSource.
/// </summary>
public class BackgroundProcessor : IDisposable
{
    private readonly CancellationTokenSource _cts = new();
    private Task? _workerTask;

    public void Start()
    {
        var token = _cts.Token;
        _workerTask = Task.Run(() => ProcessLoop(token), token);
    }

    private void ProcessLoop(CancellationToken token)
    {
        while (!token.IsCancellationRequested)
        {
            try
            {
                // Pass the token so blocking calls can be interrupted immediately
                // instead of waiting for Thread.Abort() which no longer works.
                var item = GetNextItem(token);
                ProcessItem(item, token);
            }
            catch (OperationCanceledException) when (token.IsCancellationRequested)
            {
                // Equivalent to the old ThreadAbortException catch block.
                // Unlike ThreadAbortException, this does NOT auto-rethrow,
                // so Thread.ResetAbort() is unnecessary.
                RollbackCurrentTransaction();
                break; // exit loop cleanly
            }
            finally
            {
                FlushBuffers();
            }
        }
    }

    /// <summary>
    /// Requests cancellation then waits for graceful shutdown.
    /// Replaces the old Thread.Sleep + Thread.Abort pattern.
    /// </summary>
    public async Task StopAsync(TimeSpan? timeout = null)
    {
        _cts.Cancel();

        if (_workerTask is not null)
        {
            // Wait up to the timeout for the worker to finish.
            // If it doesn't finish in time, you still know — but the task
            // isn't forcibly killed. This is by design: .NET 8 has no
            // mechanism to forcibly terminate a thread.
            var deadline = timeout ?? TimeSpan.FromSeconds(5);
            if (await Task.WhenAny(_workerTask, Task.Delay(deadline)) != _workerTask)
            {
                // Log a warning: worker didn't stop within the deadline.
                // In .NET 8 there is no fallback equivalent to Thread.Abort().
                // If this happens, the root cause is a blocking call that
                // doesn't observe the CancellationToken — fix that call.
            }
        }
    }

    public void Dispose()
    {
        _cts.Cancel();
        try { _workerTask?.Wait(TimeSpan.FromSeconds(2)); } catch { /* swallow */ }
        _cts.Dispose();
    }

    // --- Stubs showing how the token propagates ---
    private object GetNextItem(CancellationToken token)
    {
        // PITFALL: If this method blocks without checking the token,
        // cancellation won't be responsive. Always forward the token
        // to any blocking API (e.g., BlockingCollection.Take(token),
        // Channel.ReadAsync(token), SemaphoreSlim.WaitAsync(token)).
        throw new NotImplementedException();
    }

    private void ProcessItem(object item, CancellationToken token)
    {
        token.ThrowIfCancellationRequested();
        throw new NotImplementedException();
    }

    private void RollbackCurrentTransaction() => throw new NotImplementedException();
    private void FlushBuffers() => throw new NotImplementedException();
}

